from shiny import App, ui, render

app_ui = ui.page_fluid(
    ui.h2("Kleine Shiny-for-Python-App"),
    ui.input_slider("n", "Wähle eine Zahl", min=0, max=100, value=20),
    ui.output_text_verbatim("txt")
)

def server(input, output, session):
    @output
    @render.text
    def txt():
        n = input.n()
        return f"Du hast {n} gewählt. Das Quadrat ist {n*n}."

app = App(app_ui, server)
